/*
 * HELIX design tokens — see .stitch/DESIGN.md
 *
 * DDx uses Cold Steel (#3B5B7A) / Aged Brass (#A8801F) / Iron Gray (#3F4147).
 * HELIX complements with a biological palette: coral (human) + indigo (AI) + violet (connection).
 * The indigo echoes DDx's steel-blue family; coral and violet are HELIX-only territory.
 */
:root {
  --helix-human:        #C44B2F;   /* Terracotta coral — warm, organic, human */
  --helix-human-light:  #E07A5F;
  --helix-ai:           #3B6BA8;   /* Indigo — echoes DDx steel blue, more vibrant */
  --helix-ai-light:     #6B9FD4;
  --helix-connect:      #6842A8;   /* Violet — the rung/handoff color; bridges coral ↔ indigo */
  --helix-connect-light:#9B74D4;
  --helix-ink:          #1F2933;
  --helix-muted:        #55606D;
  --helix-surface:      rgba(255, 255, 255, 0.78);
  --helix-surface-strong: rgba(255, 255, 255, 0.94);
  --helix-border:       rgba(70, 82, 96, 0.16);
  --helix-shadow-soft:  0 18px 55px rgba(30, 42, 58, 0.10);
  --helix-shadow-lift:  0 24px 70px rgba(30, 42, 58, 0.16);

  /*
   * Hextra primary color — drives buttons, links, focus rings, accents.
   * Maps to --helix-ai (#3B6BA8 ≈ HSL 213deg, 48%, 45%), the indigo execution
   * strand from DESIGN.md. Grounded, technical, already part of the brand.
   */
  --primary-hue:        213deg;
  --primary-saturation: 48%;
  --primary-lightness:  40%;
}

/* Homepage IA refresh: hero loop, artifact spine, and journey cards. */
.helix-hero-equation {
  display: flex;
  flex-wrap: wrap;
  gap: 0.55rem;
  align-items: center;
  margin-top: 1.25rem;
}

.helix-hero-equation span {
  border: 1px solid color-mix(in srgb, var(--helix-ai) 26%, transparent);
  border-radius: 999px;
  padding: 0.36rem 0.7rem;
  background: rgba(255, 255, 255, 0.72);
  color: #2d5e9b;
  font-size: 0.76rem;
  font-weight: 850;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.helix-hero-equation b {
  color: color-mix(in srgb, var(--helix-connect) 70%, #2d5e9b);
}

.helix-hero-loop {
  position: relative;
  display: grid;
  width: min(30rem, 100%);
  min-height: 31rem;
  align-content: center;
  gap: 0.55rem;
  padding: 1.35rem;
  margin: 0 auto;
  border-radius: 40px;
  background:
    linear-gradient(90deg, rgba(196, 75, 47, 0.08), transparent 42%, rgba(59, 107, 168, 0.09)),
    radial-gradient(circle at 20% 20%, rgba(196, 75, 47, 0.16), transparent 36%),
    radial-gradient(circle at 82% 80%, rgba(59, 107, 168, 0.16), transparent 38%),
    rgba(255, 255, 255, 0.42);
  box-shadow: inset 0 0 0 1px rgba(128, 128, 128, 0.12), 0 28px 70px rgba(23, 36, 55, 0.12);
}

.helix-hero-loop::before {
  content: "";
  position: absolute;
  left: 50%;
  top: 3rem;
  bottom: 3rem;
  width: 2px;
  transform: translateX(-50%);
  background: linear-gradient(var(--helix-human), var(--helix-ai), var(--helix-connect));
  opacity: 0.32;
}

.helix-hero-loop::after {
  content: "";
  position: absolute;
  inset: 1.3rem;
  border: 1px solid color-mix(in srgb, var(--helix-connect) 18%, transparent);
  border-radius: 30px;
  background:
    linear-gradient(135deg, rgba(255, 255, 255, 0.65), transparent 55%);
  opacity: 0.9;
  pointer-events: none;
}

.helix-loop-center {
  position: relative;
  left: auto;
  top: auto;
  z-index: 3;
  width: fit-content;
  height: auto;
  justify-self: center;
  padding: 0.5rem 0.8rem;
  transform: none;
  border: 1px solid color-mix(in srgb, var(--helix-ai) 24%, transparent);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.94);
  color: #172033;
  font-size: 0.82rem;
  font-weight: 900;
  letter-spacing: 0.06em;
  line-height: 1.15;
  text-align: center;
  text-transform: uppercase;
  box-shadow: 0 16px 38px rgba(23, 36, 55, 0.1);
}

.helix-loop-node,
.helix-loop-role {
  position: relative;
  z-index: 4;
  width: auto;
  border: 1px solid rgba(128, 128, 128, 0.16);
  border-radius: 18px;
  padding: 0.62rem 0.74rem;
  background: rgba(255, 255, 255, 0.9);
  box-shadow: 0 18px 42px rgba(23, 36, 55, 0.11);
}

.helix-loop-node span {
  display: inline-grid;
  width: 1.4rem;
  height: 1.4rem;
  place-items: center;
  margin-bottom: 0.25rem;
  border-radius: 999px;
  background: color-mix(in srgb, var(--helix-ai) 12%, white);
  color: #2d5e9b;
  font-size: 0.68rem;
  font-weight: 900;
}

.helix-loop-node strong {
  display: block;
  color: #172033;
  font-size: 0.88rem;
  line-height: 1.15;
}

.helix-loop-node em,
.helix-loop-role small {
  display: block;
  margin-top: 0.22rem;
  color: rgba(82, 82, 91, 0.95);
  font-style: normal;
  font-size: 0.74rem;
  line-height: 1.25;
}

.helix-loop-artifacts {
  justify-self: center;
  width: 13rem;
}

.helix-loop-review {
  justify-self: end;
  width: 13rem;
}

.helix-loop-plan {
  justify-self: center;
  width: 13rem;
}

.helix-loop-runtime {
  justify-self: start;
  width: 13rem;
}

.helix-loop-evidence {
  justify-self: center;
  width: 13rem;
}

.helix-loop-role {
  z-index: 5;
  width: auto;
  border-radius: 999px;
  padding: 0.48rem 0.78rem;
  font-size: 0.66rem;
  font-weight: 900;
  letter-spacing: 0.07em;
  line-height: 1.1;
  text-transform: uppercase;
}

.helix-loop-human {
  position: absolute;
  left: 1.1rem;
  top: 1.1rem;
  color: var(--helix-human);
  border-color: color-mix(in srgb, var(--helix-human) 26%, transparent);
}

.helix-loop-agent {
  position: absolute;
  right: 1.1rem;
  top: 1.1rem;
  color: var(--helix-ai);
  border-color: color-mix(in srgb, var(--helix-ai) 26%, transparent);
}

.helix-loop-steps {
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.helix-loop-steps .helix-home-card {
  justify-content: flex-start;
  min-height: 9.75rem;
}

.helix-section-footer {
  display: flex;
  justify-content: flex-end;
  margin: 1.5rem 0 0;
}

.helix-section-footer a {
  display: inline-flex;
  align-items: center;
  gap: 0.45rem;
  color: var(--helix-ink);
  font-family: var(--helix-font-display);
  font-size: 0.9rem;
  font-weight: 700;
  letter-spacing: 0.01em;
  text-decoration: none;
}

.helix-section-footer a:hover {
  color: var(--helix-blue);
}

.helix-spine-flow {
  display: grid;
  grid-template-columns: repeat(7, minmax(0, 1fr));
  gap: 0.85rem;
  margin-top: 1.5rem;
}

.helix-spine-flow a {
  position: relative;
  display: grid;
  min-height: 9.5rem;
  align-content: space-between;
  gap: 0.75rem;
  border: 1px solid rgba(128, 128, 128, 0.16);
  border-radius: 20px;
  padding: 1rem;
  overflow: hidden;
  text-decoration: none;
  background:
    radial-gradient(circle at 50% 100%, rgba(59, 107, 168, 0.1), transparent 70%),
    rgba(255, 255, 255, 0.72);
  box-shadow: 0 16px 42px rgba(23, 36, 55, 0.08);
  transition: transform 180ms ease, border-color 180ms ease, box-shadow 180ms ease;
}

.helix-spine-flow a::after {
  content: "";
  position: absolute;
  left: 1rem;
  right: 1rem;
  top: 0;
  height: 3px;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--helix-human), var(--helix-ai), var(--helix-connect));
}

.helix-spine-flow a:hover {
  transform: translateY(-3px);
  border-color: color-mix(in srgb, var(--helix-ai) 35%, transparent);
  box-shadow: 0 22px 54px rgba(23, 36, 55, 0.13);
}

.helix-spine-flow span {
  color: #2d5e9b;
  font-size: 0.72rem;
  font-weight: 900;
  letter-spacing: 0.08em;
}

.helix-spine-flow strong {
  color: inherit;
  font-size: 1rem;
  line-height: 1.15;
}

.helix-spine-flow em {
  color: rgba(82, 82, 91, 0.95);
  font-style: normal;
  font-size: 0.78rem;
}

.helix-platform-grid {
  grid-template-columns: repeat(5, minmax(0, 1fr));
}

.helix-proof-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.dark .helix-hero-equation span,
.dark .helix-loop-center,
.dark .helix-loop-node,
.dark .helix-loop-role,
.dark .helix-spine-flow a {
  background-color: rgba(24, 24, 27, 0.86);
}

.dark .helix-loop-node strong {
  color: rgba(244, 244, 245, 0.95);
}

.dark .helix-loop-node em,
.dark .helix-loop-role small,
.dark .helix-spine-flow em {
  color: rgba(212, 212, 216, 0.82);
}

@media (max-width: 1100px) {
  .helix-loop-steps,
  .helix-platform-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .helix-spine-flow {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 760px) {
  .helix-hero-copy {
    order: 1;
  }

  .helix-hero-loop {
    order: 2;
  }

  .helix-hero-loop {
    min-height: 0;
    gap: 0.38rem;
    padding: 0.95rem;
    border-radius: 28px;

{
  "name": "helix-website-tests",
  "private": true,
  "type": "module",
  "scripts": {
    "serve:local": "bash scripts/serve-local.sh",
    "test:e2e": "playwright test",
    "test:screenshots": "playwright test --update-snapshots"
  },
  "devDependencies": {
    "@playwright/test": "^1.59.1"
  }
}

import { test, expect } from '@playwright/test'

// Helper: target the main content area to avoid TOC/sidebar duplicates
const article = (page: any) => page.locator('article')
const searchInput = (page: any) => page.getByPlaceholder('Search...').first()
const searchResults = (page: any) =>
  page.getByLabel('Search results').filter({ has: page.locator('a[href]') }).first()
const isGlossaryIndexRoute = (route: string) => /\/reference\/glossary\/?$/.test(route)

test.describe('Homepage', () => {
  test('loads with hero and three section cards', async ({ page }) => {
    await test.step('navigate to homepage', async () => {
      await page.goto('/')
    })

    await test.step('verify hero content', async () => {
      await expect(page.getByText('A methodology for')).toBeVisible()
      await expect(page.getByText('AI-assisted software')).toBeVisible()
    })

    await test.step('verify single primary CTA', async () => {
      await expect(page.getByRole('link', { name: 'Get Started' })).toBeVisible()
    })

    await test.step('verify three section cards', async () => {
      await expect(page.getByRole('heading', { name: /43 Artifacts/ })).toBeVisible()
      await expect(page.getByRole('heading', { name: /18 Cross-Cutting Concerns/ })).toBeVisible()
      await expect(page.getByRole('heading', { name: 'Why HELIX' })).toBeVisible()
    })

    await test.step('capture full-page screenshot', async () => {
      // Asciinema embed loads async, allow some pixel jitter
      await expect(page).toHaveScreenshot('homepage.png', {
        fullPage: true,
        maxDiffPixelRatio: 0.03,
      })
    })
  })
})

test.describe('Why HELIX', () => {
  test('section landing has the four subpages', async ({ page }) => {
    await page.goto('/why/')
    await expect(article(page).getByRole('link', { name: /The Problem/ })).toBeVisible()
    await expect(article(page).getByRole('link', { name: /The Thesis/ })).toBeVisible()
    await expect(article(page).getByRole('link', { name: /Principles/ })).toBeVisible()
    await expect(article(page).getByRole('link', { name: /Who it's for/ })).toBeVisible()
  })

  test('principles page covers all eight', async ({ page }) => {
    await page.goto('/why/principles/')
    await expect(page.getByRole('heading', { name: /1\.\s+Planning and execution/ })).toBeVisible()
    await expect(page.getByRole('heading', { name: /3\.\s+Authority order/ })).toBeVisible()
    await expect(page.getByRole('heading', { name: /6\.\s+Autonomy is supervised/ })).toBeVisible()
    await expect(page.getByRole('heading', { name: /8\.\s+Least power wins/ })).toBeVisible()
  })

  test('thesis page describes the methodology layer', async ({ page }) => {
    await page.goto('/why/the-thesis/')
    await expect(article(page).getByText(/methodology layer/i)).toBeVisible()
    await expect(article(page).getByText(/seven phases/i).first()).toBeVisible()
  })
})

test.describe('Artifacts', () => {
  test('index lists artifacts grouped by phase', async ({ page }) => {
    await page.goto('/artifacts/')
    // Phase headings should be visible (h2)
    await expect(page.getByRole('heading', { name: /Phase 0.*Discover/ })).toBeVisible()
    await expect(page.getByRole('heading', { name: /Phase 1.*Frame/ })).toBeVisible()
    await expect(page.getByRole('heading', { name: /Phase 6.*Iterate/ })).toBeVisible()
  })

  test('artifact pages render generation prompt and template', async ({ page }) => {
    await page.goto('/artifacts/prd/')
    await expect(page.getByRole('heading', { name: /What it is/ })).toBeVisible()
    await expect(page.getByRole('heading', { name: /Relationships/ })).toBeVisible()
    // Prompt and template are wrapped in <details>
    await expect(article(page).getByText(/generation prompt/i).first()).toBeVisible()
    await expect(article(page).getByText(/Show the template structure/i)).toBeVisible()
  })

  test('alias from old /reference/glossary/artifacts/ resolves', async ({ page }) => {
    const response = await page.request.get('/reference/glossary/artifacts/prd/')
    // Hugo aliases are HTML redirects; either 200 (rendered) or 3xx (redirect) is acceptable
    expect([200, 301, 302, 308]).toContain(response.status())
  })

  test('artifact type leaf pages keep parent activity navigation', async ({ page }) => {
    await page.setViewportSize({ width: 1800, height: 1000 })
    const sidebar = page.locator('aside').first()
    const artifactTypeLink = (path: string) => sidebar.locator(`a[href$="${path}"]`)

    await page.goto('/artifact-types/frame/prd/')
    await expect(artifactTypeLink('/artifact-types/frame/')).toBeVisible()
    await expect(artifactTypeLink('/artifact-types/frame/prd/')).toBeVisible()
    await expect(artifactTypeLink('/artifact-types/frame/feature-specification/')).toBeVisible()
    await expect(artifactTypeLink('/artifact-types/frame/pr-faq/')).toBeVisible()
    await expect(artifactTypeLink('/artifact-types/frame/prd/')).toHaveClass(
      /hextra-sidebar-active-item/,
    )
    await expect(
      artifactTypeLink('/artifact-types/frame/prd/')
        .locator('xpath=ancestor::li[1]')
        .locator('a[href^="#"]')
        .first(),
    ).toBeHidden()

    await page.goto('/artifact-types/frame/pr-faq/')
    await expect(artifactTypeLink('/artifact-types/frame/')).toBeVisible()
    await expect(artifactTypeLink('/artifact-types/frame/prd/')).toBeVisible()
    await expect(artifactTypeLink('/artifact-types/frame/feature-specification/')).toBeVisible()
    await expect(artifactTypeLink('/artifact-types/frame/pr-faq/')).toBeVisible()
    await expect(artifactTypeLink('/artifact-types/frame/pr-faq/')).toHaveClass(
      /hextra-sidebar-active-item/,
    )
    await expect(
      artifactTypeLink('/artifact-types/frame/pr-faq/')
        .locator('xpath=ancestor::li[1]')
        .locator('a[href^="#"]')
        .first(),
    ).toBeHidden()
  })
})

