/* Hero loop v2: simple visual loop, distinct from the detailed double helix. */
.helix-hero-loop {
  display: block;
  min-height: 29rem;
  padding: 0;
  overflow: hidden;
  background:
    radial-gradient(circle at 50% 50%, rgba(255, 255, 255, 0.96) 0 20%, transparent 21%),
    conic-gradient(from 225deg, rgba(196, 75, 47, 0.22), rgba(59, 107, 168, 0.24), rgba(104, 66, 168, 0.2), rgba(196, 75, 47, 0.22)),
    radial-gradient(circle at 22% 18%, rgba(196, 75, 47, 0.14), transparent 36%),
    radial-gradient(circle at 78% 82%, rgba(59, 107, 168, 0.16), transparent 38%),
    rgba(255, 255, 255, 0.5);
}

.helix-hero-loop::before {
  left: 50%;
  top: 50%;
  bottom: auto;
  width: 18rem;
  height: 18rem;
  transform: translate(-50%, -50%) rotate(-12deg);
  border: 2px solid color-mix(in srgb, var(--helix-connect) 34%, transparent);
  border-radius: 999px;
  background:
    radial-gradient(circle at 50% -1%, var(--helix-human) 0 0.28rem, transparent 0.32rem),
    radial-gradient(circle at 101% 50%, var(--helix-ai) 0 0.28rem, transparent 0.32rem),
    radial-gradient(circle at 50% 101%, var(--helix-connect) 0 0.28rem, transparent 0.32rem),
    radial-gradient(circle at -1% 50%, var(--helix-human) 0 0.28rem, transparent 0.32rem);
  opacity: 0.9;
}

.helix-hero-loop::after {
  inset: 1.35rem;
  border: 1px solid color-mix(in srgb, var(--helix-ai) 16%, transparent);
  border-radius: 34px;
  background:
    linear-gradient(135deg, rgba(255, 255, 255, 0.7), transparent 58%);
}

.helix-loop-center {
  position: absolute;
  left: 50%;
  top: 50%;
  width: 7.4rem;
  padding: 0.7rem 0.8rem;
  transform: translate(-50%, -50%);
}

.helix-loop-node {
  position: absolute;
  width: 10.6rem;
  padding: 0.78rem 0.9rem;
}

.helix-loop-node span {
  margin-bottom: 0.34rem;
}

.helix-loop-node strong {
  font-size: 1.04rem;
}

.helix-loop-artifacts {
  left: 50%;
  top: 1.4rem;
  width: 11.2rem;
  transform: translateX(-50%);
}

.helix-loop-review {
  right: 0.75rem;
  top: 50%;
  width: 11.2rem;
  transform: translateY(-50%);
}

.helix-loop-plan {
  left: 50%;
  right: auto;
  bottom: 1.4rem;
  width: 11.2rem;
  transform: translateX(-50%);
}

.helix-loop-runtime {
  left: 0.75rem;
  bottom: auto;
  top: 50%;
  width: 11.2rem;
  transform: translateY(-50%);
}

.helix-loop-evidence {
  display: none;
}

.helix-loop-human,
.helix-loop-agent {
  position: absolute;
  top: auto;
  bottom: 1rem;
  margin: 0;
}

.helix-loop-human {
  left: 1rem;
}

.helix-loop-agent {
  right: 1rem;
}

@media (max-width: 760px) {
  .helix-hero-loop {
    min-height: 31rem;
    padding: 0;
  }

  .helix-hero-loop::before {
    width: 14rem;
    height: 14rem;
  }

  .helix-loop-center {
    width: 6.7rem;
    font-size: 0.74rem;
  }

  .helix-loop-node {
    width: 8.8rem;
    padding: 0.62rem 0.68rem;
  }

  .helix-loop-node strong {
    font-size: 0.88rem;
  }

  .helix-loop-node em {
    font-size: 0.68rem;
  }

  .helix-loop-artifacts {
    top: 1rem;
  }

  .helix-loop-review {
    right: 0.45rem;
  }

  .helix-loop-plan {
    bottom: 4rem;
  }

  .helix-loop-runtime {
    left: 0.45rem;
  }

  .helix-loop-human,
  .helix-loop-agent {
    bottom: 0.8rem;
    width: auto;
    font-size: 0.58rem;
  }
}

.dark {
