  --helix-human-light:  #F4A990;
  --helix-ai:           #6B9FD4;
  --helix-ai-light:     #A3C4E8;
  --helix-connect:      #9B74D4;
  --helix-connect-light:#C3A8E8;
  --helix-ink:          #EEF2F7;
  --helix-muted:        #B9C2CF;
  --helix-surface:      rgba(20, 24, 31, 0.76);
  --helix-surface-strong: rgba(20, 24, 31, 0.94);
  --helix-border:       rgba(214, 224, 238, 0.14);
  --helix-shadow-soft:  0 18px 55px rgba(0, 0, 0, 0.28);
