/* Hero layout: SVG right of text on md+, stacked on mobile */
.helix-hero-layout {
  position: relative;
  display: flex;
  align-items: center;
  isolation: isolate;
  gap: clamp(1.5rem, 4vw, 3.5rem);
  padding: clamp(1.5rem, 4vw, 3.5rem) clamp(1rem, 2.8vw, 2.5rem) 1rem clamp(1.5rem, 4vw, 3.5rem);
  overflow: hidden;
  border-radius: 42px;
  background: #fbf6eb;
}

.dark .helix-hero-layout {
  background: #111721;
}

.helix-hero-layout::before {
  content: none;
}

.dark .helix-hero-layout::before {
  content: none;
}

.helix-hero-text,
.helix-hero-copy {
  flex: 1 1 auto;
  min-width: 0;
}

.helix-hero-copy {
  flex: 1 1 58rem;
  max-width: 62rem;
}

.helix-hero-image-panel {
  position: relative;
  flex: 0 1 min(58vw, 56rem);
  min-width: min(100%, 34rem);
  margin: clamp(-1.2rem, -1.8vw, -0.6rem) clamp(-1rem, -1.4vw, -0.35rem) clamp(-1rem, -1.4vw, -0.5rem) clamp(-1.5rem, -2vw, -0.75rem);
  overflow: hidden;
  border-radius: 0;
  background: transparent;
  box-shadow: none;
}

.helix-hero-image-panel::before {
  content: "";
  position: absolute;
  inset: 0;
  z-index: 2;
  pointer-events: none;
  background:
    linear-gradient(90deg, #fbf6eb 0%, rgba(251, 246, 235, 0.96) 8%, rgba(251, 246, 235, 0) 28%),
    linear-gradient(180deg, #fbf6eb 0%, rgba(251, 246, 235, 0) 16%, rgba(251, 246, 235, 0) 78%, #fbf6eb 100%);
}

.helix-hero-image-panel::after {
  content: "";
  position: absolute;
  inset: auto 0 0 0;
  z-index: 3;
  height: 26%;
  pointer-events: none;
  background: linear-gradient(180deg, rgba(251, 246, 235, 0), #fbf6eb 78%);
}

.helix-hero-image {
  display: block;
  width: 100%;
  aspect-ratio: 16 / 10;
  object-fit: cover;
  object-position: center right;
  filter: saturate(0.95) contrast(0.98);
  mix-blend-mode: normal;
  opacity: 0.98;
}

.helix-hero-image-dark {
