import { chromium } from 'playwright';
const browser = await chromium.launch({ headless: true });
const page = await browser.newPage({ viewport: { width: 1280, height: 900 } });
await page.goto('http://127.0.0.1:1313/');
const data = await page.evaluate(() => {
  const q = s => {
    const el = document.querySelector(s);
    const r = el.getBoundingClientRect();
    const cs = getComputedStyle(el);
    return { x: r.x, y: r.y, w: r.width, h: r.height, flex: cs.flex, maxWidth: cs.maxWidth, width: cs.width };
  };
  return {
    layout: q('.helix-hero-layout'),
    copy: q('.helix-hero-copy'),
    loop: q('.helix-hero-loop'),
    center: q('.helix-loop-center'),
    evidence: q('.helix-loop-evidence'),
    review: q('.helix-loop-review'),
    plan: q('.helix-loop-plan'),
    runtime: q('.helix-loop-runtime'),
  };
});
console.log(JSON.stringify(data, null, 2));
await browser.close();
EOF"

