/bin/zsh -lc "node --input-type=module <<'EOF'
import { chromium } from 'playwright';
const browser = await chromium.launch({ headless: true });
const page = await browser.newPage({ viewport: { width: 390, height: 1000 }, deviceScaleFactor: 1, isMobile: true });
await page.goto('http://127.0.0.1:1313/');
await page.screenshot({ path: 'test-results/current-homepage-mobile-check.png', fullPage: true });
const overlaps = await page.evaluate(() => {
  const nodes = [...document.querySelectorAll('.helix-hero-loop .helix-loop-node, .helix-hero-loop .helix-loop-center')];
  const rects = nodes.map((el) => ({ text: el.textContent.trim(), r: el.getBoundingClientRect() }));
  const pairs = [];
  for (let i = 0; i < rects.length; i++) {
    for (let j = i + 1; j < rects.length; j++) {
      const a = rects[i].r, b = rects[j].r;
      const x = Math.max(0, Math.min(a.right, b.right) - Math.max(a.left, b.left));
      const y = Math.max(0, Math.min(a.bottom, b.bottom) - Math.max(a.top, b.top));
      if (x * y > 12) pairs.push([rects[i].text, rects[j].text, Math.round(x * y)]);
    }
  }
  return pairs;
});
console.log(JSON.stringify(overlaps, null, 2));
await browser.close();
EOF"

